function solve(nums) {
    const N = nums.length;
    if (N < 3) {
        return 0;
    }

    // P is the maximum index i that can be special (1 <= i <= N-2)
    const P = N - 2; 

    // costs[i] stores the minimum cost required to make index i a peak.
    // We use 1-based indexing for costs corresponding to indices 1 through P.
    const costs = new Array(P + 1);

    for (let i = 1; i <= P; i++) {
        // Neighbors are i-1 and i+1
        // nums[i-1] and nums[i+1] are guaranteed to exist since 1 <= i <= N-2
        const neighbor_max = Math.max(nums[i - 1], nums[i + 1]);

        // Required value for nums[i] to be a peak is neighbor_max + 1
        const required_value = neighbor_max + 1;

        // Cost = max(0, required_value - current_value)
        const cost = Math.max(0, required_value - nums[i]);
        costs[i] = cost;
    }

    let min_total_cost = Infinity;

    if (P % 2 !== 0) {
        // Case 1: P is odd (N is odd). The unique Maximal Independent Set (MIS) is {1, 3, 5, ..., P}.
        let current_cost = 0;
        for (let i = 1; i <= P; i += 2) {
            current_cost += costs[i];
        }
        min_total_cost = current_cost;
    } else {
        // Case 2: P is even (N is even). There are two MISs: S_odd = {1, 3, ..., P-1} and S_even = {2, 4, ..., P}.

        // Calculate Cost for S_odd
        let cost_odd = 0;
        for (let i = 1; i <= P - 1; i += 2) {
            cost_odd += costs[i];
        }
        min_total_cost = cost_odd;

        // Calculate Cost for S_even
        let cost_even = 0;
        for (let i = 2; i <= P; i += 2) {
            cost_even += costs[i];
        }

        min_total_cost = Math.min(min_total_cost, cost_even);
    }

    return min_total_cost;
}

